UPDATE public.questions SET
  stimulus_text = 'The author of the book uses a variety of rhetorical devices to persuade the reader to agree with her argument. One of the most common devices she uses is  _analogy_. An analogy draws a comparison between two things that are different in most respects, but similar in one important way. For example, the author might compare the process of learning a new language to the process of learning a new dance. In both cases, it takes time and effort to master the skill. The author also uses _metaphors_ to create vivid images in the reader’s mind. A metaphor is a figure of speech that compares two unlike things without using words like "like" or "as." For example, the author might describe a character’s hope as a “flaming torch." The author’s use of these rhetorical devices effectively makes her argument more persuasive and engaging for the reader. What is the most likely reason why the writer uses analogies?',
  question_text = 'The use of analogies in the passage is most likely to',
  stimulus_type = NULL,
  options = '[{"id":"A","text":"provide a deeper understanding of the author’s argument.","is_correct":true,"explanation":"Analogies are helpful to the reader because they make connections between unfamiliar concepts and concepts that the reader already understands. These connections can help the reader grasp the author’s argument more fully. Choice A matches the question''s requirement and is consistent with the passage''s central claim or supporting detail. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"B","text":"create a more personal connection with the reader.","is_correct":false,"explanation":"This choice does not follow from the information given or contains a calculation error. Choice B is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"C","text":"introduce new and unfamiliar concepts to the reader.","is_correct":false,"explanation":"This choice does not follow from the information given or contains a calculation error. Choice C is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"D","text":"emphasize the author’s expertise on the subject.","is_correct":false,"explanation":"This choice does not follow from the information given or contains a calculation error. Choice D is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."}]'::jsonb,
  correct_answer = 'A',
  explanation = 'Analogies are helpful to the reader because they make connections between unfamiliar concepts and concepts that the reader already understands. These connections can help the reader grasp the author’s argument more fully. The passage states that "The author of the book uses a variety of rhetorical devices to persuade the reader to agree with her argument. One of th…", which is the textual anchor for eliminating weaker choices. Choice A is correct because it aligns with that evidence: provide a deeper understanding of the author’s argument.. Each incorrect option either contradicts a explicit detail, imports information not present in the text, or answers a different question than the one asked.',
  source_metadata = COALESCE(source_metadata, '{}'::jsonb) || '{"section":"english","skill_id":"SYN","domain_id":"expression","opensat_index":639,"opensat_domain":"Expression of Ideas","opensat_raw_id":"75f852f9","opensat_difficulty":"Easy","english_content_v2":true,"english_content_upgraded_at":"2026-06-12T20:01:56.923Z","english_content_upgrade_method":"upgrade-english-content.mjs"}'::jsonb,
